-- 1. Clone production schema to development using zero-copy clone
-- Creates dev_db.sales_clone as a clone of prod_db.sales (no data copied)
CREATE SCHEMA dev_db.sales_clone CLONE prod_db.sales;

-- 2. Restrict writes on production schema
-- Revoke DML privileges on all existing tables in the production schema
REVOKE INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA prod_db.sales FROM ROLE DEV;
-- Revoke DML privileges on all future tables created in the production schema
REVOKE INSERT, UPDATE, DELETE ON FUTURE TABLES IN SCHEMA prod_db.sales FROM ROLE DEV;

-- 3. Grant read-only access to the clone for role DEV
-- Grant USAGE on the database to allow access to schemas within it
GRANT USAGE ON DATABASE dev_db TO ROLE DEV;
-- Grant USAGE on the cloned schema to allow accessing objects within it
GRANT USAGE ON SCHEMA dev_db.sales_clone TO ROLE DEV;
-- Grant SELECT on all existing tables in the cloned schema
GRANT SELECT ON ALL TABLES IN SCHEMA dev_db.sales_clone TO ROLE DEV;
-- Grant SELECT on all future tables created in the cloned schema
GRANT SELECT ON FUTURE TABLES IN SCHEMA dev_db.sales_clone TO ROLE DEV;

-- 4. Set data retention on the clone to 7 days
-- Note: Clones inherit source retention but can be overridden at schema level
ALTER SCHEMA dev_db.sales_clone SET DATA_RETENTION_TIME_IN_DAYS = 7;

-- 5. Verify isolation between production and clone
-- Insert a test row into the clone
INSERT INTO dev_db.sales_clone.customers (id, name) VALUES (9999, 'TEST_ISOLATION');
-- Verify the row exists in clone
SELECT id, name FROM dev_db.sales_clone.customers WHERE id = 9999;
-- Verify the row does NOT exist in production (proving isolation)
SELECT id, name FROM prod_db.sales.customers WHERE id = 9999;
-- Clean up the test row
DELETE FROM dev_db.sales_clone.customers WHERE id = 9999;

